import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix default marker icon bug in Leaflet + Webpack
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
  iconUrl:       'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
  shadowUrl:     'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
});

// Blue marker for focused/selected property
const blueIcon = new L.Icon({
  iconUrl:       'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-blue.png',
  shadowUrl:     'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
  iconSize:     [25, 41],
  iconAnchor:   [12, 41],
  popupAnchor:  [1, -34],
});

// Red marker for normal properties
const redIcon = new L.Icon({
  iconUrl:       'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-red.png',
  shadowUrl:     'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
  iconSize:     [25, 41],
  iconAnchor:   [12, 41],
  popupAnchor:  [1, -34],
});

// Helper component to fly map to focused property
const FlyToProperty = ({ lat, lng }) => {
  const map = useMap();
  useEffect(() => {
    if (lat && lng) {
      map.flyTo([parseFloat(lat), parseFloat(lng)], 15, { duration: 1.5 });
    }
  }, [lat, lng, map]);
  return null;
};

const PropertyMap = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();

  const focusLat = searchParams.get('lat');
  const focusLng = searchParams.get('lng');
  const focusId  = searchParams.get('id');

  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const markerRefs = useRef({});

  const defaultCenter = focusLat && focusLng
    ? [parseFloat(focusLat), parseFloat(focusLng)]
    : [10.7769, 106.7009]; // HCM City

  useEffect(() => {
    const fetchProperties = async () => {
      try {
        setLoading(true);
        const response = await fetch('http://localhost:5001/api/properties/map');
        const data = await response.json();
        if (data.success) {
          setProperties(data.data);
        }
      } catch (error) {
        console.error('Error fetching properties:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchProperties();
  }, []);

  // Auto-open popup for focused property after markers render
  useEffect(() => {
    if (focusId && properties.length > 0) {
      setTimeout(() => {
        const ref = markerRefs.current[parseInt(focusId)];
        if (ref) {
          ref.openPopup();
        }
      }, 500);
    }
  }, [properties, focusId]);

  const formatPrice = (price) => {
    return new Intl.NumberFormat('vi-VN', {
      style: 'currency',
      currency: 'VND',
      minimumFractionDigits: 0
    }).format(price);
  };

  return (
    <div style={{ padding: '1rem' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem' }}>
        <button
          onClick={() => navigate(-1)}
          style={{
            background: 'none',
            border: '1px solid #ccc',
            borderRadius: '6px',
            padding: '6px 12px',
            cursor: 'pointer',
            fontSize: '14px'
          }}
        >
          ← Quay Lại
        </button>
        <h1 style={{ margin: 0 }}>🗺️ Bản Đồ Bất Động Sản</h1>
        {loading && <span style={{ color: '#888', fontSize: '14px' }}>Đang tải...</span>}
      </div>

      <div style={{ borderRadius: '12px', overflow: 'hidden', border: '1px solid #ddd' }}>
        <MapContainer
          center={defaultCenter}
          zoom={focusLat && focusLng ? 15 : 12}
          style={{ width: '100%', height: '600px' }}
        >
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />

          {/* Fly to focused property */}
          {focusLat && focusLng && (
            <FlyToProperty lat={focusLat} lng={focusLng} />
          )}

          {properties.map((property) => {
            const isFocused = focusId && property.id === parseInt(focusId);
            const lat = property.position?.lat ?? property.latitude;
            const lng = property.position?.lng ?? property.longitude;

            if (!lat || !lng) return null;

            return (
              <Marker
                key={property.id}
                position={[parseFloat(lat), parseFloat(lng)]}
                icon={isFocused ? blueIcon : redIcon}
                ref={(ref) => { if (ref) markerRefs.current[property.id] = ref; }}
              >
                <Popup minWidth={220}>
                  <div style={{ lineHeight: '1.6' }}>
                    <h3 style={{ margin: '0 0 6px', fontSize: '14px' }}>
                      {property.title}
                    </h3>
                    <p style={{ margin: '0 0 4px', fontWeight: 'bold', color: '#e53935' }}>
                      {formatPrice(property.price)}
                    </p>
                    <p style={{ margin: '0 0 4px', fontSize: '12px', color: '#555' }}>
                      📍 {property.address || property.location}
                    </p>
                    {property.distance && (
                      <p style={{ margin: '0 0 4px', fontSize: '12px', color: '#1976d2' }}>
                        🚗 {property.distance.toFixed(2)} km
                      </p>
                    )}
                    <a
                      href={`/properties/${property.id}`}
                      style={{
                        display: 'inline-block',
                        marginTop: '6px',
                        color: '#1976d2',
                        fontSize: '12px',
                        textDecoration: 'none',
                        fontWeight: 'bold'
                      }}
                    >
                      Xem Chi Tiết →
                    </a>
                  </div>
                </Popup>
              </Marker>
            );
          })}
        </MapContainer>
      </div>

      <p style={{ marginTop: '0.5rem', fontSize: '12px', color: '#888', textAlign: 'right' }}>
        Tìm thấy {properties.length} bất động sản trên bản đồ
      </p>
    </div>
  );
};

export default PropertyMap;
